            //
            aOrbiterH = ((aOrbiterH + aOrbiterI) + 0x35C5E857502D031DULL) + aPhaseCOrbiterUpdateSaltC[((aIndex + 27U)) & 31];
            aOrbiterK = (aOrbiterK ^ aOrbiterH) ^ 0x7C918937C50F0103ULL;
