            aIngress = aIngress + (RotL64(aOrbiterC, 54U) ^ aOrbiterB);
            aIngress = aIngress + (RotL64(aOrbiterK, 19U) ^ aOrbiterH);
            aIngress = aIngress + (aOrbiterD ^ RotL64(aOrbiterA, 27U));
