            aOrbiterJ = (aOrbiterJ + aOrbiterD) + 0xB446EB57BC40A9B7ULL;
            aOrbiterE = ((aOrbiterE ^ aOrbiterJ) ^ 0xDA7D2BD848604637ULL) ^ aPhaseAOrbiterUpdateSaltF[((aIndex + 23U)) & 31];
