            aOrbiterG = (aOrbiterG + aOrbiterE) + 0x6BC795D7C286E02CULL;
            aOrbiterH = (aOrbiterH ^ aOrbiterG) ^ 0x44466B0228AAAA5CULL;
            aOrbiterH = RotL64((aOrbiterH * 0xFBBBF93D829F92B9ULL), 23U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterK) + 0x563E8CAA254302EBULL;
            aOrbiterD = (aOrbiterD ^ aOrbiterC) ^ 0x5F0D08C787764C2CULL;
            aOrbiterD = RotL64((aOrbiterD * 0x819F242DD1DEC063ULL), 19U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterC) + 0x3BAD41664C174257ULL;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterH) ^ 0xB74FB1BBBF99481AULL;
            aOrbiterJ = RotL64((aOrbiterJ * 0x608D416399316703ULL), 47U);
