            aOrbiterC = RotL64((aOrbiterC * 0xBB4503D233B9F2B5ULL), 11U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterD) + 0x8896B9E2320DB864ULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterC) ^ 0xD8D2F1C0B12D6DD9ULL;
