            //
            aOrbiterE = (aOrbiterE + aOrbiterF) + 0xCA894954997C3631ULL;
            aOrbiterD = ((aOrbiterD ^ aOrbiterE) ^ 0x939A0F1524B64AAAULL) ^ aPhaseEOrbiterUpdateSaltC[((aIndex + 9U)) & 31];
            aOrbiterD = RotL64((aOrbiterD * 0xA6A88D8D45E9141FULL), 51U);
