            //
            aOrbiterH = (aOrbiterH + aOrbiterK) + 0x0F5A8EB76BFB63D6ULL;
            aOrbiterG = ((aOrbiterG ^ aOrbiterH) ^ 0xAC2CD2223A4D8EBBULL) ^ aPhaseEOrbiterUpdateSaltA[(((31U - aIndex) + 5U)) & 31];
