            aCross = (RotL64(aOperationLaneA[((S_BLOCK1 - aIndex + 9563U)) & S_BLOCK1], 57U) ^ RotL64(aOperationLaneD[((S_BLOCK1 - aIndex + 5701U)) & S_BLOCK1], 37U));
            aCross ^= RotL64(aSnowLaneC[((S_BLOCK1 - aIndex + 8241U)) & S_BLOCK1], 26U);
